Great question! Production deployments need defense in depth - securing both the application and the web server. Directory listing can be enabled at multiple layers, and there are several related misconfigurations to address.

**PRODUCTION PATTERN**:

```python
# app/config.py - Environment-aware configuration
import os
from pathlib import Path

class Config:
    """Base configuration with secure defaults"""
    SECRET_KEY = os.environ.get('SECRET_KEY')  # Must be set in production
    UPLOAD_FOLDER = Path('/var/www/uploads')
    MAX_CONTENT_LENGTH = 16 * 1024 * 1024

    # Security headers
    SESSION_COOKIE_SECURE = True
    SESSION_COOKIE_HTTPONLY = True
    SESSION_COOKIE_SAMESITE = 'Strict'

    # Allowed file types
    ALLOWED_EXTENSIONS = {'.pdf', '.png', '.jpg', '.jpeg', '.gif'}

    # Rate limiting
    RATELIMIT_DEFAULT = "100 per hour"
    RATELIMIT_STORAGE_URL = "redis://localhost:6379"

class ProductionConfig(Config):
    """Production-specific security settings"""
    DEBUG = False
    TESTING = False

    # Enforce SECRET_KEY is set
    def __init__(self):
        if not self.SECRET_KEY:
            raise ValueError("SECRET_KEY must be set in production")

class DevelopmentConfig(Config):
    """Development settings - still secure by default"""
    DEBUG = False  # Even in dev, don't enable debug
    SECRET_KEY = 'dev-key-not-for-production'
