Serving static files is common, but the default Go file server enables directory listing which can expose sensitive files and internal structure to attackers.

**VULNERABLE CODE**:

```go
package main

import (
	"log"
	"net/http"
)

func main() {
	// VULNERABLE: Default FileServer enables directory listing
	// Navigating to /static/ shows all files in the directory
	fs := http.FileServer(http.Dir("./static"))
	http.Handle("/static/", http.StripPrefix("/static/", fs))

	// VULNERABLE: Serving from root exposes entire directory
	http.Handle("/files/", http.StripPrefix("/files/", 
		http.FileServer(http.Dir("./uploads"))))

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Attack Scenario**:
```text
Attacker navigates to: http://example.com/static/

Server returns HTML listing:
- config.json.bak
- database_backup.sql
- .env
- admin_credentials.txt
- internal_api_keys.json
```

**Why This Is Dangerous**:
- Exposes directory structure revealing application internals
- Backup files often contain credentials or sensitive data
- Hidden files (.env, .git) may be accidentally exposed
- Attackers can enumerate all available files for targeted attacks

**SECURE VERSION**:

```go
package main

import (
	"log"
	"net/http"
	"os"
	"path/filepath"
	"strings"
)

// neuteredFileSystem prevents directory listing
type neuteredFileSystem struct {
	fs http.FileSystem
}

func (nfs neuteredFileSystem) Open(path string) (http.File, error) {
	f, err := nfs.fs.Open(path)
	if err != nil {
		return nil, err
	}

	// Check if path is a directory
	s, err := f.Stat()
	if err != nil {
		f.Close()
		return nil, err
	}

	if s.IsDir() {
		// Look for index.html in directory
		index := filepath.Join(path, "index.html")
		if _, err := nfs.fs.Open(index); err != nil {
			// No index.html - close and return 404
			f.Close()
			return nil, os.ErrNotExist
		}
	}

	return f, nil
}

func main() {
	// SECURE: Wrap FileServer with neutered filesystem
	fs := neuteredFileSystem{http.Dir("./static")}
	http.Handle("/static/", http.StripPrefix("/static/", http.FileServer(fs)))

	log.Println("Server starting on :8080")
	log.Fatal(http.ListenAndServe(":8080", nil))
}
```

**Key Security Controls**:
- Custom filesystem wrapper intercepts directory requests
- Returns 404 for directories without index.html instead of listing
- Directory structure remains hidden from attackers
- Legitimate file access still works normally

Excellent question! Production file servers need multiple layers: disable directory listing, block sensitive file patterns, validate paths against traversal attacks, and log all access attempts.

**PRODUCTION PATTERN**:

```go
package main

import (
	"context"
	"log"
	"net/http"
	"os"
	"path/filepath"
	"regexp"
	"strings"
	"time"
)

// SecurityConfig holds file server security settings
type SecurityConfig struct {
	BlockedPatterns   []*regexp.Regexp
	AllowedExtensions map[string]bool
	MaxPathLength     int
	EnableLogging     bool
}

var defaultConfig = SecurityConfig{
	BlockedPatterns: []*regexp.Regexp{
		regexp.MustCompile(`(?i)\.(env|git|svn|htaccess|htpasswd|bak|backup|old|orig|swp|tmp|log|sql|conf|config|ini)$`),
		regexp.MustCompile(`(?i)^\.`),                    // Hidden files
		regexp.MustCompile(`(?i)(password|secret|key|credential)`), // Sensitive names
		regexp.MustCompile(`(?i)\~$`),                    // Vim backup files
	},
	AllowedExtensions: map[string]bool{
		".html": true, ".css": true, ".js": true,
		".png": true, ".jpg": true, ".jpeg": true,
		".gif": true, ".svg": true, ".ico": true,
		".woff": true, ".woff2": true, ".ttf": true,
		".pdf": true, ".txt": true,
	},
	MaxPathLength: 255,
	EnableLogging: true,
}

// SecureFileSystem implements http.FileSystem with security controls
type SecureFileSystem struct {
	root   http.FileSystem
	config SecurityConfig
	logger *log.Logger
}

func NewSecureFileSystem(root string, config SecurityConfig) *SecureFileSystem {
	return &SecureFileSystem{
		root:   http.Dir(root),
		config: config,
		logger: log.New(os.Stdout, "[FILE-ACCESS] ", log.LstdFlags|log.Lshortfile),
	}
}

func (sfs *SecureFileSystem) Open(name string) (http.File, error) {
	// Layer 1: Path length check
	if len(name) > sfs.config.MaxPathLength {
		sfs.logAccess(name, "BLOCKED", "path too long")
		return nil, os.ErrPermission
	}

	// Layer 2: Clean and validate path (prevent traversal)
	cleanPath := filepath.Clean(name)
	if strings.Contains(cleanPath, "..") {
		sfs.logAccess(name, "BLOCKED", "path traversal attempt")
		return nil, os.ErrPermission
	}

	// Layer 3: Check blocked patterns
	for _, pattern := range sfs.config.BlockedPatterns {
		if pattern.MatchString(name) {
			sfs.logAccess(name, "BLOCKED", "blocked pattern match")
			return nil, os.ErrNotExist // Return 404, not 403 (security through obscurity)
		}
	}

	// Layer 4: Whitelist extension check
	ext := strings.ToLower(filepath.Ext(name))
	if ext != "" && !sfs.config.AllowedExtensions[ext] {
		sfs.logAccess(name, "BLOCKED", "extension not allowed: "+ext)
		return nil, os.ErrNotExist
	}

	// Open the file
	f, err := sfs.root.Open(cleanPath)
	if err != nil {
		sfs.logAccess(name, "NOT_FOUND", err.Error())
		return nil, err
	}

	// Layer 5: Prevent directory listing
	stat, err := f.Stat()
	if err != nil {
		f.Close()
		return nil, err
	}

	if stat.IsDir() {
		// Check for index.html
		index := filepath.Join(cleanPath, "index.html")
		if _, err := sfs.root.Open(index); err != nil {
			sfs.logAccess(name, "BLOCKED", "directory listing prevented")
			f.Close()
			return nil, os.ErrNotExist
		}
	}

	sfs.logAccess(name, "ALLOWED", "")
	return f, nil
}

func (sfs *SecureFileSystem) logAccess(path, status, reason string) {
	if sfs.config.EnableLogging {
		if reason != "" {
			sfs.logger.Printf("%s %s - %s", status, path, reason)
		} else {
			sfs.logger.Printf("%s %s", status, path)
		}
	}
}

// SecurityHeadersMiddleware adds security headers to responses
func SecurityHeadersMiddleware(next http.Handler) http.Handler {
	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		w.Header().Set("X-Content-Type-Options", "nosniff")
		w.Header().Set("X-Frame-Options", "DENY")
		w.Header().Set("Content-Security-Policy", "default-src 'self'")
		w.Header().Set("Cache-Control", "public, max-age=3600")
		next.ServeHTTP(w, r)
	})
}

// RateLimitMiddleware prevents enumeration attacks
func RateLimitMiddleware(next http.Handler, requestsPerSecond int) http.Handler {
	limiter := make(chan struct{}, requestsPerSecond)

	go func() {
		ticker := time.NewTicker(time.Second / time.Duration(requestsPerSecond))
		for range ticker.C {
			select {
			case limiter <- struct{}{}:
			default:
			}
		}
	}()

	return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		select {
		case <-limiter:
			next.ServeHTTP(w, r)
		case <-r.Context().Done():
			return
		case <-time.After(time.Second):
			http.Error(w, "Too Many Requests", http.StatusTooManyRequests)
		}
	})
}

func main() {
	// Initialize secure file system
	sfs := NewSecureFileSystem("./public", defaultConfig)
	fileServer := http.FileServer(sfs)

	// Apply middleware chain
	handler := http.StripPrefix("/static/", fileServer)
	handler = SecurityHeadersMiddleware(handler).(http.Handler)
	handler = RateLimitMiddleware(handler, 100).(http.Handler)

	http.Handle("/static/", handler)

	// Health check endpoint
	http.HandleFunc("/health", func(w http.ResponseWriter, r *http.Request) {
		w.WriteHeader(http.StatusOK)
		w.Write([]byte("OK"))
	})

	server := &http.Server{
		Addr:         ":8080",
		ReadTimeout:  10 * time.Second,
		WriteTimeout: 10 * time.Second,
		IdleTimeout:  120 * time.Second,
	}

	log.Println("Secure file server starting on :8080")
	log.Fatal(server.ListenAndServe())
}
```

