# Nginx configuration - /etc/nginx/sites-available/myapp
server {
    listen 443 ssl http2;
    server_name example.com;
    root /var/www/html/public;

    # Disable directory listing globally
    autoindex off;

    # Hide Nginx version
    server_tokens off;

    # Security headers
    add_header X-Content-Type-Options "nosniff" always;
    add_header X-Frame-Options "DENY" always;
    add_header X-XSS-Protection "1; mode=block" always;

    # Block access to hidden files and directories
    location ~ /\. {
        deny all;
        access_log off;
        log_not_found off;
    }

    # Block sensitive file extensions
    location ~* \.(env|sql|bak|backup|log|old|conf|ini|git|svn)$ {
        deny all;
        access_log /var/log/nginx/blocked_access.log;
    }

    # Block sensitive directories
    location ~ ^/(config|logs|backup|vendor|node_modules)/ {
        deny all;
    }

    # PHP handling
    location ~ \.php$ {
        fastcgi_pass unix:/var/run/php/php8.2-fpm.sock;
        fastcgi_param SCRIPT_FILENAME $document_root$fastcgi_script_name;
        include fastcgi_params;

        # Prevent PHP execution in upload directories
        location ~ ^/uploads/.*\.php$ {
            deny all;
        }
    }

    # Serve static files with security controls
    location /uploads {
        internal;  # Only accessible via X-Accel-Redirect
    }
}
