```php
<?php
// Secure File Access Controller - /var/www/html/app/Controllers/FileController.php

declare(strict_types=1);

namespace App\Controllers;

use App\Services\FileSecurityService;
use App\Services\AuditLogger;
use App\Exceptions\UnauthorizedAccessException;
use App\Exceptions\FileNotFoundException;

class FileController
{
    private const ALLOWED_EXTENSIONS = ['pdf', 'jpg', 'jpeg', 'png', 'gif', 'doc', 'docx'];
    private const MAX_PATH_LENGTH = 255;
    private const UPLOAD_BASE_PATH = '/var/www/html/storage/uploads';

    private FileSecurityService $securityService;
    private AuditLogger $auditLogger;

    public function __construct(
        FileSecurityService $securityService,
        AuditLogger $auditLogger
    ) {
        $this->securityService = $securityService;
        $this->auditLogger = $auditLogger;
    }

    public function downloadFile(string $requestedPath, int $userId): void
    {
        try {
            // LAYER 1: Input validation
            $sanitizedPath = $this->validateAndSanitizePath($requestedPath);

            // LAYER 2: Path traversal protection
            $resolvedPath = $this->resolveSecurePath($sanitizedPath);

            // LAYER 3: Authorization check
            if (!$this->securityService->userCanAccessFile($userId, $resolvedPath)) {
                $this->auditLogger->logUnauthorizedAccess(
                    $userId,
                    $requestedPath,
                    $_SERVER['REMOTE_ADDR']
                );
                throw new UnauthorizedAccessException('Access denied');
            }

            // LAYER 4: File existence and type validation
            $this->validateFileExists($resolvedPath);
            $this->validateFileExtension($resolvedPath);

            // LAYER 5: Audit successful access
            $this->auditLogger->logFileAccess($userId, $resolvedPath, 'download');

            // LAYER 6: Secure file delivery
            $this->serveFileSecurely($resolvedPath);

        } catch (UnauthorizedAccessException $e) {
            http_response_code(403);
            echo json_encode(['error' => 'Access denied']);
            exit;
        } catch (FileNotFoundException $e) {
            http_response_code(404);
            echo json_encode(['error' => 'File not found']);
            exit;
        } catch (\Exception $e) {
            error_log("File access error: " . $e->getMessage());
            http_response_code(500);
            echo json_encode(['error' => 'Internal server error']);
            exit;
        }
    }

    private function validateAndSanitizePath(string $path): string
    {
        // Remove null bytes (poison null byte attack)
        $path = str_replace("\0", '', $path);

        // Check path length
        if (strlen($path) > self::MAX_PATH_LENGTH) {
            throw new \InvalidArgumentException('Path too long');
        }

        // Block directory traversal patterns
        $dangerousPatterns = [
            '../',
            '..\\',
            '..',
            '%2e%2e',
            '%252e%252e',
            '..../',
            '..%00',
            '..%c0%af',
            '..%c1%9c'
        ];

        $lowerPath = strtolower($path);
        foreach ($dangerousPatterns as $pattern) {
            if (strpos($lowerPath, strtolower($pattern)) !== false) {
                $this->auditLogger->logSecurityEvent(
                    'path_traversal_attempt',
                    ['original_path' => $path, 'ip' => $_SERVER['REMOTE_ADDR']]
                );
                throw new \InvalidArgumentException('Invalid path');
            }
        }

        // Only allow alphanumeric, dash, underscore, dot, forward slash
        if (!preg_match('/^[a-zA-Z0-9_\-\.\/ ]+$/', $path)) {
            throw new \InvalidArgumentException('Invalid characters in path');
        }

        return $path;
    }

    private function resolveSecurePath(string $sanitizedPath): string
    {
        // Build the full path
        $fullPath = self::UPLOAD_BASE_PATH . '/' . ltrim($sanitizedPath, '/');

        // Resolve to absolute path (resolves any remaining . or ..)
        $resolvedPath = realpath($fullPath);

        // Verify the resolved path is still within allowed directory
        if ($resolvedPath === false) {
            throw new FileNotFoundException('File not found');
        }

        // CRITICAL: Ensure resolved path starts with allowed base path
        if (strpos($resolvedPath, realpath(self::UPLOAD_BASE_PATH)) !== 0) {
            $this->auditLogger->logSecurityEvent(
                'path_traversal_bypass_attempt',
                [
                    'requested' => $sanitizedPath,
                    'resolved' => $resolvedPath,
                    'ip' => $_SERVER['REMOTE_ADDR']
                ]
            );
            throw new UnauthorizedAccessException('Access denied');
        }

        return $resolvedPath;
    }

    private function validateFileExists(string $path): void
    {
        if (!file_exists($path) || !is_file($path) || !is_readable($path)) {
            throw new FileNotFoundException('File not found');
        }
    }

    private function validateFileExtension(string $path): void
    {
        $extension = strtolower(pathinfo($path, PATHINFO_EXTENSION));

        if (!in_array($extension, self::ALLOWED_EXTENSIONS, true)) {
            throw new UnauthorizedAccessException('File type not allowed');
        }

        // Validate actual MIME type matches extension
        $finfo = new \finfo(FILEINFO_MIME_TYPE);
        $mimeType = $finfo->file($path);

        $allowedMimes = [
            'pdf' => 'application/pdf',
            'jpg' => 'image/jpeg',
            'jpeg' => 'image/jpeg',
            'png' => 'image/png',
            'gif' => 'image/gif',
            'doc' => 'application/msword',
            'docx' => 'application/vnd.openxmlformats-officedocument.wordprocessingml.document'
        ];

        if (!isset($allowedMimes[$extension]) || $allowedMimes[$extension] !== $mimeType) {
            $this->auditLogger->logSecurityEvent(
                'mime_type_mismatch',
                ['path' => $path, 'extension' => $extension, 'mime' => $mimeType]
            );
            throw new UnauthorizedAccessException('File type mismatch');
        }
    }

    private function serveFileSecurely(string $path): void
    {
        // Clear any previous output
        if (ob_get_level()) {
            ob_end_clean();
        }

        $filename = basename($path);
        $filesize = filesize($path);
        $mimeType = mime_content_type($path);

        // Security headers
        header('Content-Type: ' . $mimeType);
        header('Content-Disposition: attachment; filename="' . addslashes($filename) . '"');
        header('Content-Length: ' . $filesize);
        header('X-Content-Type-Options: nosniff');
        header('Content-Security-Policy: default-src \'none\'');
        header('Cache-Control: private, no-cache, no-store, must-revalidate');
        header('Pragma: no-cache');
        header('Expires: 0');

        // Use X-Accel-Redirect for Nginx (more efficient)
        if (isset($_SERVER['SERVER_SOFTWARE']) && strpos($_SERVER['SERVER_SOFTWARE'], 'nginx') !== false) {
            header('X-Accel-Redirect: /internal-files/' . ltrim($path, '/'));
            return;
        }

        // Fallback: stream file in chunks
        $handle = fopen($path, 'rb');
        while (!feof($handle)) {
            echo fread($handle, 8192);
            flush();
        }
        fclose($handle);
    }
