```nginx
# nginx.conf - Production configuration with monitoring
user appuser;
worker_processes auto;
error_log /var/log/nginx/error.log warn;
pid /tmp/nginx.pid;

events {
    worker_connections 1024;
    use epoll;
}

http {
    include /etc/nginx/mime.types;
    default_type application/octet-stream;

    # Security headers
    server_tokens off;
    more_clear_headers Server;

    # Custom log format for security monitoring
    log_format security_json escape=json '{
        "timestamp": "$time_iso8601",
        "client_ip": "$remote_addr",
        "request_method": "$request_method",
        "request_uri": "$request_uri",
        "status": $status,
        "body_bytes_sent": $body_bytes_sent,
        "request_time": $request_time,
        "user_agent": "$http_user_agent",
        "referer": "$http_referer",
        "request_id": "$request_id",
        "suspicious": "$is_suspicious"
    }';

    # Map suspicious patterns for monitoring
    map $request_uri $is_suspicious {
        default "false";
        ~*\.\./ "true";
        ~*/\.  "true";
        ~*\.(bak|backup|sql|env|git|svn) "true";
        ~*/admin "true";
        ~*/config "true";
        ~*/backup "true";
    }

    # Rate limiting zones
    limit_req_zone $binary_remote_addr zone=general:10m rate=10r/s;
    limit_req_zone $binary_remote_addr zone=downloads:10m rate=2r/s;
    limit_conn_zone $binary_remote_addr zone=conn_limit:10m;

    server {
        listen 8080;
        server_name _;

        # Access log with security format
        access_log /var/log/nginx/access.log security_json;
        access_log /var/log/nginx/security/suspicious.log security_json if=$is_suspicious;

        # Global security settings
        autoindex off;

        # Security headers
        add_header X-Content-Type-Options "nosniff" always;
        add_header X-Frame-Options "DENY" always;
        add_header X-XSS-Protection "1; mode=block" always;
        add_header Content-Security-Policy "default-src 'self'" always;
        add_header Referrer-Policy "strict-origin-when-cross-origin" always;

        # Health check endpoint
        location /health {
            access_log off;
            return 200 '{"status":"healthy"}';
            add_header Content-Type application/json;
        }

        # Public files - most permissive
        location /public/ {
            alias /var/www/public/;
            autoindex off;
            limit_req zone=general burst=20 nodelay;
            limit_conn conn_limit 10;

            # Only serve specific file types
            location ~* \.(html|css|js|png|jpg|jpeg|gif|ico|svg|woff|woff2)$ {
                expires 7d;
                add_header Cache-Control "public, immutable";
            }

            # Block everything else
            location ~ . {
                return 404;
            }
        }

        # Assets - static resources
        location /assets/ {
            alias /var/www/assets/;
            autoindex off;
            limit_req zone=general burst=20 nodelay;

            # Whitelist allowed extensions
            if ($request_filename !~* \.(css|js|png|jpg|jpeg|gif|svg|woff|woff2|ttf|eot)$) {
                return 404;
            }

            expires 30d;
            add_header Cache-Control "public, immutable";
        }

        # Downloads - rate limited
        location /downloads/ {
            alias /var/www/downloads/;
            autoindex off;
            limit_req zone=downloads burst=5 nodelay;
            limit_conn conn_limit 2;

            # Only allow specific download extensions
            if ($request_filename !~* \.(pdf|zip|tar\.gz)$) {
                return 404;
            }

            # Force download
            add_header Content-Disposition "attachment";
        }

        # Block common enumeration attempts
        location ~* /(\.|backup|bak|old|temp|tmp|config|admin|test|dev) {
            access_log /var/log/nginx/security/blocked.log security_json;
            return 404;
        }

        # Block sensitive file extensions
        location ~* \.(sql|bak|backup|log|conf|config|env|ini|yml|yaml|json|xml|htaccess|htpasswd|git|svn)$ {
            access_log /var/log/nginx/security/blocked.log security_json;
            return 404;
        }

        # Catch-all - return 404 for anything not explicitly allowed
        location / {
            return 404;
        }

        # Custom error pages (don't reveal server info)
        error_page 403 404 /404.html;
        error_page 500 502 503 504 /50x.html;

        location = /404.html {
            internal;
            root /var/www/public/errors;
        }

        location = /50x.html {
            internal;
            root /var/www/public/errors;
        }
    }
}
