  contentSecurityPolicy: {
    directives: {
      defaultSrc: ["'self'"],
      scriptSrc: ["'self'"],
      styleSrc: ["'self'", "'unsafe-inline'"],
      imgSrc: ["'self'", "data:", "https:"],
      objectSrc: ["'none'"]
    }
  },
  crossOriginResourcePolicy: { policy: "same-origin" }
}));

app.disable('x-powered-by');

// Rate limiting for static file requests
const staticLimiter = rateLimit({
  windowMs: 15 * 60 * 1000, // 15 minutes
  max: 1000, // limit each IP to 1000 requests per windowMs
  message: { error: 'Too many requests' },
  standardHeaders: true,
  legacyHeaders: false
});

// Directory configuration with access controls
const STATIC_DIRECTORIES = {
  public: {
    path: path.join(__dirname, 'public'),
    allowedExtensions: ['.html', '.css', '.js', '.ico', '.svg'],
    requireAuth: false,
    maxFileSize: 5 * 1024 * 1024 // 5MB
  },
  images: {
    path: path.join(__dirname, 'assets', 'images'),
    allowedExtensions: ['.jpg', '.jpeg', '.png', '.gif', '.webp'],
    requireAuth: false,
    maxFileSize: 10 * 1024 * 1024 // 10MB
  },
  documents: {
    path: path.join(__dirname, 'secure', 'documents'),
    allowedExtensions: ['.pdf', '.docx', '.xlsx'],
    requireAuth: true,
    maxFileSize: 50 * 1024 * 1024 // 50MB
  }
};

// SECURE: Path traversal prevention middleware
function sanitizePath(basePath) {
  return (req, res, next) => {
    const requestedPath = req.path;

    // Block null bytes (used in some path traversal attacks)
    if (requestedPath.includes('\0')) {
      logger.warn({
        event: 'path_traversal_attempt',
        ip: req.ip,
        path: requestedPath,
        type: 'null_byte'
      });
      return res.status(400).json({ error: 'Invalid request' });
    }

    // Decode and normalize the path
    let decodedPath;
    try {
      decodedPath = decodeURIComponent(requestedPath);
    } catch (e) {
      logger.warn({
        event: 'path_traversal_attempt',
        ip: req.ip,
        path: requestedPath,
        type: 'invalid_encoding'
      });
      return res.status(400).json({ error: 'Invalid request' });
    }

    // Block path traversal sequences
    const traversalPatterns = ['../', '..\\', '%2e%2e', '%252e%252e'];
    if (traversalPatterns.some(pattern => 
        decodedPath.toLowerCase().includes(pattern))) {
      logger.warn({
        event: 'path_traversal_attempt',
        ip: req.ip,
        path: requestedPath,
        decodedPath: decodedPath,
        type: 'traversal_sequence'
      });
      return res.status(403).json({ error: 'Access denied' });
    }

    // Resolve the full path and verify it's within the base directory
    const fullPath = path.resolve(basePath, '.' + decodedPath);
    const normalizedBase = path.resolve(basePath);

    if (!fullPath.startsWith(normalizedBase + path.sep) && 
        fullPath !== normalizedBase) {
      logger.warn({
        event: 'path_traversal_attempt',
        ip: req.ip,
        requestedPath: requestedPath,
        resolvedPath: fullPath,
        basePath: normalizedBase,
        type: 'path_escape'
      });
      return res.status(403).json({ error: 'Access denied' });
    }

    req.sanitizedPath = fullPath;
    next();
  };
}

// File type validation middleware
function validateFileType(config) {
  return (req, res, next) => {
    const ext = path.extname(req.path).toLowerCase();

    if (!ext) {
      // No extension - might be trying to access directory
      logger.info({
        event: 'directory_access_attempt',
        ip: req.ip,
        path: req.path
      });
      return res.status(404).json({ error: 'Resource not found' });
    }

    if (!config.allowedExtensions.includes(ext)) {
      logger.warn({
        event: 'blocked_file_type',
        ip: req.ip,
        path: req.path,
        extension: ext
      });
      return res.status(403).json({ error: 'File type not allowed' });
    }

    next();
  };
}

// Authentication middleware for protected directories
function requireAuthentication(req, res, next) {
  const authHeader = req.headers.authorization;

  if (!authHeader || !authHeader.startsWith('Bearer ')) {
    logger.warn({
      event: 'unauthorized_access_attempt',
      ip: req.ip,
      path: req.path
    });
    return res.status(401).json({ error: 'Authentication required' });
  }

  // Implement your token validation here
  // This is a placeholder - use proper JWT validation in production
  const token = authHeader.substring(7);
  if (!validateToken(token)) {
    return res.status(403).json({ error: 'Invalid token' });
  }

  next();
}

function validateToken(token) {
  // Implement proper JWT validation
  return token && token.length > 0;
}

// Access logging middleware
function logAccess(directoryName) {
  return (req, res, next) => {
    const startTime = Date.now();

    res.on('finish', () => {
      logger.info({
        event: 'file_access',
        directory: directoryName,
        path: req.path,
        ip: req.ip,
        userAgent: req.headers['user-agent'],
        statusCode: res.statusCode,
        responseTime: Date.now() - startTime
      });
    });

    next();
  };
}

// Configure routes for each directory
Object.entries(STATIC_DIRECTORIES).forEach(([name, config]) => {
  const middlewares = [
    staticLimiter,
    logAccess(name),
    sanitizePath(config.path),
    validateFileType(config)
  ];

