      setHeaders: (res, filePath) => {
        // Add security headers for specific file types
        if (filePath.endsWith('.pdf')) {
          res.setHeader('Content-Disposition', 'inline');
        }
        res.setHeader('X-Content-Type-Options', 'nosniff');
      }
    })
  );
});

// Catch-all 404 handler - generic response
app.use((req, res) => {
  logger.info({
    event: '404_not_found',
    ip: req.ip,
    path: req.path,
    method: req.method
  });
  res.status(404).json({ error: 'Resource not found' });
});

// Error handler - don't leak internal details
app.use((err, req, res, next) => {
  logger.error({
    event: 'server_error',
    ip: req.ip,
    path: req.path,
    error: err.message,
    stack: err.stack
  });
  res.status(500).json({ error: 'Internal server error' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  logger.info({ event: 'server_start', port: PORT });
  console.log(`Secure file server running on port ${PORT}`);
});
```

