Spring Boot requires both configuration and programmatic security controls. Here's a comprehensive production-ready approach with defense in depth.

**PRODUCTION PATTERN - Spring Boot Security Configuration**:

```java
package com.example.security.config;

import org.springframework.boot.web.embedded.tomcat.TomcatServletWebServerFactory;
import org.springframework.boot.web.server.WebServerFactoryCustomizer;
import org.springframework.context.annotation.Bean;
import org.springframework.context.annotation.Configuration;
import org.springframework.security.config.annotation.web.builders.HttpSecurity;
import org.springframework.security.config.annotation.web.configuration.EnableWebSecurity;
import org.springframework.security.web.SecurityFilterChain;
import org.springframework.security.web.header.writers.XXssProtectionHeaderWriter;
import org.springframework.web.servlet.config.annotation.ResourceHandlerRegistry;
import org.springframework.web.servlet.config.annotation.WebMvcConfigurer;
import org.apache.catalina.Context;
import org.apache.catalina.Wrapper;
import org.slf4j.Logger;
import org.slf4j.LoggerFactory;

import javax.servlet.*;
import javax.servlet.http.HttpServletRequest;
import javax.servlet.http.HttpServletResponse;
import java.io.IOException;
import java.util.Arrays;
import java.util.List;

@Configuration
@EnableWebSecurity
public class SecurityConfiguration implements WebMvcConfigurer {

    private static final Logger securityLogger = LoggerFactory.getLogger("SECURITY_AUDIT");

    private static final List<String> BLOCKED_EXTENSIONS = Arrays.asList(
        ".bak", ".backup", ".old", ".orig", ".temp", ".tmp",
        ".swp", ".swo", ".log", ".sql", ".conf", ".config",
        ".yml", ".yaml", ".properties", ".env", ".git"
    );

    // Disable directory listing at Tomcat level
    @Bean
    public WebServerFactoryCustomizer<TomcatServletWebServerFactory> tomcatCustomizer() {
        return factory -> factory.addContextCustomizers(context -> {
            // Disable directory listing on default servlet
            Wrapper defaultServlet = (Wrapper) context.findChild("default");
            if (defaultServlet != null) {
                defaultServlet.addInitParameter("listings", "false");
                defaultServlet.addInitParameter("showServerInfo", "false");
            }
            securityLogger.info("Tomcat directory listing disabled");
        });
    }

    // Comprehensive security filter chain
    @Bean
    public SecurityFilterChain filterChain(HttpSecurity http) throws Exception {
        http
            .authorizeHttpRequests(authz -> authz
                // Block access to sensitive paths
                .antMatchers("/WEB-INF/**").denyAll()
                .antMatchers("/META-INF/**").denyAll()
                .antMatchers("/**/*.bak").denyAll()
                .antMatchers("/**/*.backup").denyAll()
                .antMatchers("/**/*.old").denyAll()
                .antMatchers("/**/*.properties").denyAll()
                .antMatchers("/**/*.yml").denyAll()
                .antMatchers("/**/*.env").denyAll()
                .antMatchers("/**/.*").denyAll() // Hidden files
                .anyRequest().permitAll()
            )
            .headers(headers -> headers
                // Security headers to prevent information disclosure
                .xssProtection(xss -> xss
                    .headerValue(XXssProtectionHeaderWriter.HeaderValue.ENABLED_MODE_BLOCK))
                .contentTypeOptions(contentType -> {})
                .frameOptions(frame -> frame.deny())
                .httpStrictTransportSecurity(hsts -> hsts
                    .maxAgeInSeconds(31536000)
                    .includeSubDomains(true))
                // Hide server information
                .addHeaderWriter((request, response) -> {
                    response.setHeader("Server", "");
                    response.setHeader("X-Powered-By", "");
                })
            );

        return http.build();
    }

    // Custom filter for additional path protection
    @Bean
    public Filter sensitivePathFilter() {
        return new SensitivePathFilter();
    }

    private class SensitivePathFilter implements Filter {
        @Override
        public void doFilter(ServletRequest request, ServletResponse response, 
                           FilterChain chain) throws IOException, ServletException {
            HttpServletRequest httpRequest = (HttpServletRequest) request;
            HttpServletResponse httpResponse = (HttpServletResponse) response;
            String path = httpRequest.getRequestURI().toLowerCase();

            // Check for directory traversal attempts
            if (path.contains("..") || path.contains("%2e%2e")) {
                securityLogger.warn("Directory traversal attempt blocked: {} from IP: {}",
                    path, httpRequest.getRemoteAddr());
                httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, "Access Denied");
                return;
            }

            // Block sensitive file extensions
            for (String ext : BLOCKED_EXTENSIONS) {
                if (path.endsWith(ext)) {
                    securityLogger.warn("Sensitive file access blocked: {} from IP: {}",
                        path, httpRequest.getRemoteAddr());
                    httpResponse.sendError(HttpServletResponse.SC_FORBIDDEN, "Access Denied");
                    return;
                }
            }

            // Check for path ending with / (potential directory listing attempt)
            if (path.endsWith("/") && !path.equals("/")) {
                securityLogger.info("Directory access attempt: {} from IP: {}",
                    path, httpRequest.getRemoteAddr());
            }

            chain.doFilter(request, response);
        }
    }

    // Secure static resource handling
    @Override
    public void addResourceHandlers(ResourceHandlerRegistry registry) {
        registry.addResourceHandler("/static/**")
            .addResourceLocations("classpath:/static/")
            .setCachePeriod(3600);
        // Do NOT add resource handlers for root or sensitive paths
    }
}
```

